B.Ts=new A.P(B.k5,["\u0420\u0410\u041a\u0410\u0410\u0422\u042b",'\u0421\u043b\u0438\u0448\u043a\u043e\u043c \u0442\u0435\u043c\u043d\u043e. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043a\u043d\u043e\u043f\u043a\u0443 "+1"',"\u0412\u0441\u0451 \u043d\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u043e, \u043c\u043e\u0436\u0435\u0442\u0435 \u043c\u043e\u043b\u0438\u0442\u044c\u0441\u044f",'\u0424\u0440\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f \u043a\u0430\u043c\u0435\u0440\u0430 \u043d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d\u0430, \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043a\u043d\u043e\u043f\u043a\u0443 "+1"',"\u041f\u043e\u0434\u043e\u0436\u0434\u0438\u0442\u0435, \u043d\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u043c \u043a\u0430\u043c\u0435\u0440\u0443","\u041d\u0410\u0421\u0422\u0420\u041e\u0419\u041a\u0418","\u0420\u0435\u0436\u0438\u043c \u043e\u0442\u043b\u0430\u0434\u043a\u0438","\u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044f \u043f\u0440\u0438 \u0441\u0443\u0434\u0436\u0443\u0434\u0435",'\u0420\u0435\u0436\u0438\u043c "\u041d\u0435 \u0431\u0435\u0441\u043f\u043e\u043a\u043e\u0438\u0442\u044c"',"\u041f\u0440\u043e\u0439\u0442\u0438 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u0437\u0430\u043d\u043e\u0432\u043e","\u042f\u0440\u043a\u043e\u0441\u0442\u044c: ","\u041d\u0435\u0441\u043e\u0432\u043f\u0430\u0434\u0435\u043d\u0438\u0435: ","\u0414\u043e\u0431\u0440\u043e \u043f\u043e\u0436\u0430\u043b\u043e\u0432\u0430\u0442\u044c! \u041f\u043e\u043b\u043e\u0436\u0438\u0442\u0435 \u0442\u0435\u043b\u0435\u0444\u043e\u043d \u043d\u0430 \u043f\u043e\u043b \u043f\u0435\u0440\u0435\u0434 \u043a\u043e\u0432\u0440\u0438\u043a\u043e\u043c (\u043c\u0435\u0441\u0442\u043e\u043c \u0437\u0435\u043c\u043d\u043e\u0433\u043e \u043f\u043e\u043a\u043b\u043e\u043d\u0430) \u044d\u043a\u0440\u0430\u043d\u043e\u043c \u0432\u0432\u0435\u0440\u0445, \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043d\u0430 \u0443\u0440\u043e\u0432\u043d\u0435 \u0433\u0440\u0443\u0434\u0438.\n\n\u0423 \u0432\u0430\u0441 \u0435\u0441\u0442\u044c \u0432\u0440\u0435\u043c\u044f, \u043f\u043e\u043a\u0430 \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u0433\u043e\u0440\u0438\u0442 \u0436\u0451\u043b\u0442\u044b\u0439 \u0442\u0435\u043a\u0441\u0442, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u0438\u043d\u044f\u0442\u044c \u0438\u0441\u0445\u043e\u0434\u043d\u043e\u0435 \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0435. \u0415\u0441\u043b\u0438 \u0432\u044b \u0443\u0441\u043f\u0435\u043b\u0438 \u0437\u0430\u043d\u044f\u0442\u044c \u0435\u0433\u043e \u0438 \u0437\u0430\u0433\u043e\u0440\u0435\u043b\u0441\u044f \u0437\u0435\u043b\u0451\u043d\u044b\u0439 \u0442\u0435\u043a\u0441\u0442, \u0442\u043e \u043c\u043e\u0436\u0435\u0442\u0435 \u043d\u0430\u0447\u0438\u043d\u0430\u0442\u044c \u043c\u043e\u043b\u0438\u0442\u044c\u0441\u044f.","\u0424\u0440\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f \u043a\u0430\u043c\u0435\u0440\u0430 \u0431\u0443\u0434\u0435\u0442 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043a\u0430\u0436\u0434\u044b\u0439 \u043f\u043e\u043a\u043b\u043e\u043d (\u0441\u0443\u0434\u0436\u0443\u0434), \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u043f\u0440\u0438\u0431\u043b\u0438\u0436\u0430\u0435\u0442\u0435\u0441\u044c \u043a \u044d\u043a\u0440\u0430\u043d\u0443.","\u0415\u0441\u043b\u0438 \u0432 \u043a\u043e\u043c\u043d\u0430\u0442\u0435 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0442\u0435\u043c\u043d\u043e, \u0430\u0432\u0442\u043e\u043f\u043e\u0434\u0441\u0447\u0451\u0442 \u043c\u043e\u0436\u0435\u0442 \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c \u043d\u0435\u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043d\u043e (\u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0434\u0438\u0442 \u0432\u0430\u0441). \u0412 \u044d\u0442\u043e\u043c \u0441\u043b\u0443\u0447\u0430\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043a\u043d\u043e\u043f\u043a\u0443 \xab+1\xbb \u0432\u043d\u0438\u0437\u0443 \u044d\u043a\u0440\u0430\u043d\u0430.","\u0414\u043e\u0431\u0440\u043e \u043f\u043e\u0436\u0430\u043b\u043e\u0432\u0430\u0442\u044c! \u0414\u043b\u044f \u043f\u043e\u0434\u0441\u0447\u0451\u0442\u0430 \u0440\u0430\u043a\u0430\u0430\u0442\u043e\u0432 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043a\u043d\u043e\u043f\u043a\u0443 \xab+1\xbb \u0432\u043d\u0438\u0437\u0443 \u044d\u043a\u0440\u0430\u043d\u0430.\n\n\u0412 \u0431\u043b\u0438\u0436\u0430\u0439\u0448\u0435\u0435 \u0432\u0440\u0435\u043c\u044f \u043c\u044b \u043f\u043e\u0441\u0442\u0430\u0440\u0430\u0435\u043c\u0441\u044f \u0434\u043e\u0431\u0430\u0432\u0438\u0442\u044c \u0444\u0443\u043d\u043a\u0446\u0438\u044e \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u043f\u043e\u0434\u0441\u0447\u0451\u0442\u0430 \u0440\u0430\u043a\u0430\u0430\u0442\u043e\u0432","\u0412\u043d\u0438\u043c\u0430\u043d\u0438\u0435!\n\n\u0415\u0441\u043b\u0438 \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u0438\u043b\u0438, \u0447\u0442\u043e \u0432 \u0441\u0442\u0440\u043e\u043a\u0435 \xab\u041d\u0435\u0441\u043e\u0432\u043f\u0430\u0434\u0435\u043d\u0438\u0435\xbb \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u0432\u044b\u0448\u0430\u0435\u0442 10, \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0435\u0441\u044c \u0432 \u0432\u044b\u043f\u0440\u044f\u043c\u043b\u0435\u043d\u043d\u043e\u043c \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0438, \u044d\u0442\u043e \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043e \u043f\u0440\u043e\u0438\u0437\u043e\u0448\u0451\u043b \u0441\u0431\u043e\u0439 \u0430\u043b\u0433\u043e\u0440\u0438\u0442\u043c\u0430. \u0412 \u0442\u0430\u043a\u043e\u043c \u0441\u043b\u0443\u0447\u0430\u0435 \u0441\u043b\u0435\u0434\u0443\u0435\u0442 \u043d\u0430\u0436\u0430\u0442\u044c \u043a\u043d\u043e\u043f\u043a\u0443 \xab\u041f\u0435\u0440\u0435\u0437\u0430\u043f\u0443\u0441\u0442\u0438\u0442\u044c\xbb - \u043e\u043d\u0430 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u043e\u0434 \u0441\u0447\u0451\u0442\u0447\u0438\u043a\u043e\u043c \u0440\u0430\u043a\u0430\u0430\u0442\u043e\u0432.\n\n\u0414\u0430\u043d\u043d\u043e\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0441\u043e\u0437\u0434\u0430\u043d\u043e \u0434\u043b\u044f \u043f\u043e\u043c\u043e\u0449\u0438 \u0432 \u043c\u043e\u043b\u0438\u0442\u0432\u0435 \u0438 \u043d\u0435 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u0443\u0435\u0442 \u0430\u0431\u0441\u043e\u043b\u044e\u0442\u043d\u043e \u0431\u0435\u0437\u043e\u0448\u0438\u0431\u043e\u0447\u043d\u044b\u0439 \u0443\u0447\u0451\u0442 \u043f\u043e\u043a\u043b\u043e\u043d\u043e\u0432. \u041d\u0430\u0436\u0438\u043c\u0430\u044f \xab\u0414\u0430\u043b\u0435\u0435\xbb, \u0432\u044b \u0441\u043e\u0433\u043b\u0430\u0448\u0430\u0435\u0442\u0435\u0441\u044c \u0441 \u0442\u0435\u043c, \u0447\u0442\u043e \u0441\u0430\u043c\u043e\u0441\u0442\u043e\u044f\u0442\u0435\u043b\u044c\u043d\u043e \u043d\u0435\u0441\u0451\u0442\u0435 \u043f\u043e\u043b\u043d\u0443\u044e \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0432\u044b\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u044f \u043c\u043e\u043b\u0438\u0442\u0432\u044b \u0438 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u044b\u0435 \u043f\u0440\u043e\u043f\u0443\u0449\u0435\u043d\u043d\u044b\u0435 \u0441\u0443\u0434\u0436\u0443\u0434\u044b.","\u0412\u044b \u0432\u0441\u0435\u0433\u0434\u0430 \u043c\u043e\u0436\u0435\u0442\u0435 \u0437\u0430\u043d\u043e\u0432\u043e \u043f\u0440\u043e\u0439\u0442\u0438 \u044d\u0442\u043e \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0434\u0440\u0443\u0433\u0438\u0435 \u043f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u044b \u0432 \u043d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0430\u0445 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f.\n\n\u041f\u0440\u0438\u044f\u0442\u043d\u043e\u0433\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f!","\u0414\u0430\u043b\u0435\u0435","\u041d\u0430\u0447\u0430\u0442\u044c","\u0441\u0435\u043a"],t.w)
B.ys=new A.P(B.k5,["RAKATS",'Too dark. Use the "+1" button',"Everything is fine, you can pray",'Front camera not found, use the "+1" button',"Just a moment, setting up the camera","SETTINGS","Debug Mode","Vibration on Sajdah","Do Not Disturb Mode","Restart Tutorial","Brightness: ","Mismatch: ","Welcome! Place your phone on the floor in front of the prayer mat (the place of prostration) screen up, approximately at chest level.\n\nWhile the yellow text is displayed on the screen, you have time to take your starting position. If you have successfully taken it and the text turns green, you can begin your prayer.","The front camera will automatically detect each prostration (sajdah) as you move closer to the screen.",'If the room is too dark, the auto-count might work incorrectly (the app will notify you). In this case, use the manual "+1" button.','Welcome! To count rakats, use the "+1" button at the bottom of the screen.\n\nWe will try to add an automatic rakat counting feature in the near future.','Warning!\n\nIf you notice that the value in the "Mismatch" row exceeds 10 while you are in an upright position, it means the algorithm has encountered a glitch. In this case, you should tap the "Restart" button located right below the rakats counter.\n\nThis application is created to assist during prayer and does not guarantee entirely error-free tracking of prostrations. By tapping "Next", you agree that you bear full personal responsibility for the correctness of your prayer and any missed sujuds.',"You can restart this tutorial at any time or change other preferences in the application settings.\n\nHave a blessed prayer!","Next","Start","sec"],t.w)
B.Tt=new A.P(B.k5,["\u0627\u0644\u0631\u0643\u0639\u0627\u062a",'\u0645\u0638\u0644\u0645 \u062c\u062f\u0627\u064b. \u0627\u0633\u062a\u062e\u062f\u0645 \u0632\u0631 "+1"',"\u0643\u0644 \u0634\u064a\u0621 \u062c\u064a\u062f\u060c \u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u0635\u0644\u0627\u0629",'\u0627\u0644\u0643\u0627\u0645\u064a\u0631\u0627 \u0627\u0644\u0623\u0645\u0627\u0645\u064a\u0629 \u063a\u064a\u0631 \u0645\u0648\u062c\u0648\u062f\u0629\u060c \u0627\u0633\u062a\u062e\u062f\u0645 \u0632\u0631 "+1"',"\u0627\u0646\u062a\u0638\u0631\u060c \u064a\u062a\u0645 \u0625\u0639\u062f\u0627\u062f \u0627\u0644\u0643\u0627\u0645\u064a\u0631\u0627","\u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a","\u0648\u0636\u0639 \u0627\u0644\u062a\u0635\u062d\u064a\u062d","\u0627\u0644\u0627\u0647\u062a\u0632\u0627\u0632 \u0639\u0646\u062f \u0627\u0644\u0633\u062c\u0648\u062f","\u0648\u0636\u0639 \u0639\u062f\u0645 \u0627\u0644\u0625\u0632\u0639\u0627\u062c","\u0625\u0639\u0627\u062f\u0629 \u0627\u0644\u062f\u0644\u064a\u0644 \u0627\u0644\u062a\u0639\u0644\u064a\u0645\u0438\u0439","\u0627\u0644\u0633\u0637\u0648\u0639: ","\u0639\u062f\u0645 \u0627\u0644\u062a\u0637\u0627\u0628\u0642: ","\u0645\u0631\u062d\u0628\u0627\u064b \u0628\u0643! \u0636\u0639 \u0627\u0644\u0647\u0627\u062a\u0641 \u0639\u0644\u0649 \u0627\u0644\u0623\u0631\u0636 \u0623\u0645\u0627\u0645 \u0633\u062c\u0627\u062f\u0629 \u0627\u0644\u0635\u0644\u0627\u0629 (\u0645\u0648\u0636\u0639 \u0627\u0644\u0633\u062c\u0648\u062f) \u0648\u0627\u0644\u0634\u0627\u0634\u0629 \u0645\u062a\u062c\u0647\u0629 \u0644\u0623\u0639\u0644\u0645\u060c \u0639\u0644\u0649 \u0645\u0633\u062a\u0648\u0649 \u0627\u0644\u0635\u062f\u0631 \u062a\u0642\u0631\u064a\u0628\u0627\u064b.\n\n\u0644\u062f\u064a\u0643 \u0627\u0644\u0648\u0642\u062a \u0644\u0627\u062a\u062e\u0627\u0630 \u0627\u0644\u0648\u0636\u0639\u064a\u0629 \u0627\u0644\u0628\u062f\u0626\u064a\u0629 \u0637\u0627\u0644\u0645\u0627 \u0623\u0646 \u0627\u0644\u0646\u0635 \u0627\u0644\u0623\u0635\u0641\u0631 \u064a\u0636\u064a\u0621 \u043d\u0430 \u0627\u0644\u0634\u0627\u0634\u0629. \u0625\u0630\u0627 \u062a\u0645\u0643\u0646\u062a \u0645\u0646 \u0627\u062a\u062e\u0627\u0630\u0647\u0627 \u0648\u062a\u062d\u0648\u0644 \u0627\u0644\u0646\u0635 \u0625\u0644\u0649 \u0627\u0644\u0644\u0648\u0646 \u0627\u0644\u0623\u062e\u0636\u0631\u060c \u0641\u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u0628\u062f\u0621 \u0641\u064a \u0627\u0644\u0635\u0644\u0627\u0629.","\u0633\u062a\u0642\u0648\u0645 \u0627\u0644\u0643\u0627\u0645\u064a\u0631\u0627 \u0627\u0644\u0623\u0645\u0627\u0645\u064a\u0629 \u0628\u062a\u0644\u0642\u0627\u0626\u064a\u0629 \u0628\u0627\u062d\u062a\u0633\u0627\u0628 \u0643\u0644 \u0633\u062c\u062f\u0629 \u0639\u0646\u062f \u0627\u0642\u062a\u0631\u0627\u0628\u0643 \u0645\u0646 \u0627\u0644\u0634\u0627\u0634\u0629.",'\u0625\u0630\u0627 \u0643\u0627\u0646\u062a \u0627\u0644\u0625\u0636\u0627\u0621\u0629 \u062e\u0627\u0641\u062a\u0629 \u062c\u062f\u0627\u064b\u060c \u0642\u062f \u0644\u0627 \u064a\u0639\u0645\u0644 \u0627\u0644\u062d\u0633\u0627\u0628 \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a \u0628\u0634\u0643\u0644 \u0635\u062d\u064a\u062d (\u0633\u064a\u0642\u0648\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0628\u062a\u0646\u0628\u064a\u0647\u0643). \u0641\u064a \u0647\u0630\u0647 \u0627\u0644\u062d\u0627\u0644\u0629\u060c \u0627\u0633\u062a\u062e\u062f\u0645 \u0632\u0631 "+1" \u0627\u0644\u064a\u062f\u0648\u064a.',"\u0645\u0631\u062d\u0628\u0627\u064b \u0628\u0643! \u0644\u062d\u0633\u0627\u0628 \u0627\u0644\u0631\u0643\u0639\u0627\u062a\u060c \u0627\u0633\u062a\u062e\u062f\u0645 \u0632\u0631 \xab+1\xbb \u0641\u064a \u0623\u0633\u0641\u0644 \u0627\u0644\u0634\u0627\u0634\u0629.\n\n\u0641\u064a \u0627\u0644\u0645\u0633\u062a\u0642\u0628\u0644 \u0627\u0644\u0642\u0631\u064a\u0628\u060c \u0633\u0646\u062d\u0627\u0648\u0644 \u0625\u0636\u0627\u0641\u0629 \u0645\u064a\u0632\u0629 \u0627\u0644\u062d\u0633\u0627\u0628 \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a \u0644\u0644\u0631\u0643\u0639\u0627\u062a.","\u062a\u0646\u0628\u064a\u0647!\n\n\u0625\u0630\u0627 \u0644\u0627\u062d\u0638\u062a \u0623\u0646 \u0627\u0644\u0642\u064a\u0645\u0629 \u0641\u064a \u062e\u0627\u0646\u0629 \xab\u0639\u062f\u0645 \u0627\u0644\u062a\u0637\u0627\u0628\u0642\xbb \u062a\u062a\u062c\u0627\u0648\u0632 10 \u0648\u0623\u0646\u062a \u0641\u064a \u0648\u0636\u0639 \u0645\u0633\u062a\u0642\u064a\u0645\u060c \u0641\u0647\u0630\u0627 \u064a\u0639\u0646\u064a \u062d\u062f\u0648\u062b \u062e\u0644\u0644 \u0641\u064a \u0627\u0644\u062e\u0648\u0627\u0631\u0632\u0645\u064a\u0629. \u0641\u064a \u0647\u0630\u0647 \u0627\u0644\u062d\u0627\u0644\u0629\u060c \u064a\u0631\u062c\u0649 \u0627\u0644\u0636\u063a\u0637 \u0639\u0644\u0649 \u0632\u0631 \xab\u0625\u0639\u0627\u062f\u0629 \u0627\u0644\u062a\u0634\u063a\u064a\u0644\xbb \u0627\u0644\u0645\u0648\u062c\u0648\u062f \u0623\u0633\u0641\u0644 \u0639\u062f\u0627\u062f \u0627\u0644\u0631\u0643\u0639\u0627\u062a.\n\n\u0647\u0630\u0627 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u062a\u0645 \u062a\u0637\u0648\u064a\u0631\u0647 \u0644\u0644\u0645\u0633\u0627\u0639\u062f\u0629 \u0641\u064a \u0627\u0644\u0635\u0644\u0627\u0629 \u0648\u0644\u0627 \u064a\u0636\u0645\u0646 \u062f\u0642\u0629 \u0645\u0637\u0644\u0642\u0629 \u0641\u064a \u062d\u0633\u0627\u0628 \u0627\u0644\u0633\u062c\u062f\u0627\u062a. \u0628\u0627\u0644\u0636\u063a\u0637 \u0639\u0644\u0649 \xab\u0627\u0644\u062a\u0627\u0644\u064a\xbb\u060c \u0641\u0625\u0646\u0643 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0623\u0646\u0643 \u062a\u062a\u062d\u0645\u0644 \u0627\u0644\u0645\u0633\u0624\u0648\u0644\u064a\u0629 \u0627\u0644\u0643\u0627\u0645\u0644\u0629 \u0639\u0646 \u0635\u062d\u0629 \u0635\u0644\u0627\u062a\u0643 \u0648\u0623\u064a \u0633\u062c\u062f\u0627\u062a \u0642\u062f \u062a\u064f\u0646\u0633\u0649.","\u064a\u0645\u0643\u0646\u0643 \u062f\u0627\u0626\u0645\u0627\u064b \u0625\u0639\u0627\u062f\u0629 \u062a\u0634\u063a\u064a\u0644 \u0647\u0630\u0627 \u0627\u0644\u062a\u0639\u0644\u064a\u0645\u064a \u0623\u0648 \u062a\u063a\u064a\u064a\u0631 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0623\u062e\u0631\u0649 \u0645\u0646 \u0642\u0627\u0626\u0645\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a.\n\n\u0646\u0631\u062c\u0648 \u0644\u0643 \u0635\u0644\u0627\u0629 \u0645\u0642\u0628\u0648\u0644\u0629!","\u0627\u0644\u062a\u0627\u0644\u064a","\u0627\u0628\u062f\u0623","\u062b\u0627\u0646\u064a\u0629"],t.w)
